#!/usr/bin/env python3
"""
Arregla la transparencia excesiva de .svc-modal (modal 'Editar servicio'
y modal de detalle de cita, que comparten esa clase). Quedo demasiado
transparente por el vidrio intensificado V2; ahora vuelve a tener un
fondo solido (rgba(15,12,28,0.92)) conservando el brillo del mouse.

Ejecutar desde la raiz del repo (carpeta que contiene 'src'):
    python3 apply_svc_modal_opacity_fix.py
"""

import base64
from pathlib import Path

GLOBALS_CSS_B64 = """"""

def main():
    p = Path("src/app/globals.css")
    p.write_bytes(base64.b64decode(GLOBALS_CSS_B64))
    print(f"escrito: {p} ({p.stat().st_size} bytes)")
    print()
    print("Listo. Luego:")
    print("  git add -A")
    print("  git commit -m 'Arregla transparencia excesiva del modal de servicios/citas'")
    print("  git push")

if __name__ == "__main__":
    main()